// Auto-embedded ESP Publico Banner (Medium) as a data URI so the font loads
// inside the sandboxed embed iframe (null origin), where a self-hosted .otf
// fetched by relative URL would be CORS-blocked. Mirrors the esp_logo.js
// data-URI pattern. Injects the @font-face; the CSS hooks in index.html do
// the rest. Publico Banner is licensed to ESP; do not redistribute.
(function(){
  var src = 'url(data:font/otf;base64,) format("opentype")';
  var css = "@font-face{font-family:'Publico Banner';font-weight:400 600;font-style:normal;font-display:swap;src:" + src + ";}";
  var s = document.createElement("style"); s.setAttribute("data-esp-font","publico-banner"); s.appendChild(document.createTextNode(css));
  document.head.appendChild(s);
})();
